#include <bits/stdc++.h>

#define ll long long int
using namespace std;

bool three_collide(int start, int end, vector < pair < int, pair < int, int >>> & arr) {
    map < int, int > freq;
    for (int i = start; i <= end; i++) {
        freq[arr[i].second.first]++;
        freq[arr[i].second.second + 1]--;
    }
    int prev = 0;
    for (auto it: freq) {
        prev += it.second;
        if (prev >= 3) return true;
    }
    return false;
}

void solve() {
    int n;
    cin >> n;

    vector < pair < int, pair < int, int >>> arr(n);
    for (int i = 0; i < n; i++) cin >> arr[i].second.first >> arr[i].second.second >> arr[i].first;
    sort(arr.begin(), arr.end());

    int i = 0;
    while (i < n) {
        int start = i;
        i = i + 1;
        while (i < n && arr[i].first == arr[i - 1].first) i++;
        int end = i - 1;
        if (three_collide(start, end, arr)) {
            cout << "NO\n";
            return;
        }
    }
    cout << "YES\n";
    return;
}

int main() {
    int t = 1;
    cin >> t;

    while (t--) solve();
}
